define i64 @one_hint(ptr %p) {
  %a = load i64, ptr %p, align 4
  %b = load i64, ptr %p, align 4, !mem.cache_hint !0
  %c = add i64 %a, %b
  ret i64 %c
}

!0 = !{i32 0, !1}
!1 = !{!"nvvm.l1_eviction", !"first"}

define i64 @both_hint(ptr %p) {
  %a = load i64, ptr %p, align 4, !mem.cache_hint !0
  %b = load i64, ptr %p, align 4, !mem.cache_hint !0
  %c = add i64 %a, %b
  ret i64 %c
}

!0 = !{i32 0, !1}
!1 = !{!"nvvm.l1_eviction", !"first"}

define i64 @diff_hint(ptr %p) {
  %a = load i64, ptr %p, align 4, !mem.cache_hint !0
  %b = load i64, ptr %p, align 4, !mem.cache_hint !2
  %c = add i64 %a, %b
  ret i64 %c
}

!0 = !{i32 0, !1}
!1 = !{!"nvvm.l1_eviction", !"first"}
!2 = !{i32 0, !3}
!3 = !{!"nvvm.l1_eviction", !"last"}

define i32 @cast_load_preserve_hint(ptr %p) {
  %l = load float, ptr %p, align 4, !mem.cache_hint !0
  %c = bitcast float %l to i32
  ret i32 %c
}

!0 = !{i32 0, !1}
!1 = !{!"nvvm.l1_eviction", !"first"}

define i32 @speculate_keeps_hint(i1 %c, ptr align 4 dereferenceable(4) %p) {
entry:
  br i1 %c, label %if, label %join

if:                                               ; preds = %entry
  %v = load i32, ptr %p, align 4, !mem.cache_hint !0
  br label %join

join:                                             ; preds = %if, %entry
  %phi = phi i32 [ %v, %if ], [ 0, %entry ]
  ret i32 %phi
}

!0 = !{i32 0, !1}
!1 = !{!"nvvm.l1_eviction", !"first"}

define void @key_not_string(ptr %p) {
  %v = load i32, ptr %p, align 4, !mem.cache_hint !0
  ret void
}

!0 = !{i32 0, !1}
!1 = !{i32 0, !"first"}

define void @non_memory_op(i32 %x, i32 %y) {
  %z = add i32 %x, %y, !mem.cache_hint !0
  ret void
}

!0 = !{i32 0, !1}
!1 = !{!"nvvm.l1_eviction", !"first"}

